mapper.update:
UPDATE board
   SET views = views + 1
 WHERE rqst_no = #{rqstNo}

UPDATE board
   SET title    = #{title}
     , cont     = #{cont}
     , upt_dt   = NOW()
     , secret   = #{secret}
 WHERE rqst_no  = #{rqstNo}
   AND board_type = 'YOUTH'

UPDATE board
   SET order_no = order_no + 1
 WHERE group_no = #{groupNo}
   AND order_no >= #{orderNo}
   AND board_type = 'YOUTH'

UPDATE board
   SET is_deleted = TRUE
 WHERE rqst_no = #{id}

